create.perform:
const lever = world.getEntity('item:rusty-lever');
const turnstile = world.getEntity('item:stuck-turnstile');
const gate = world.getEntity('exit:gate:north');

if (!lever || !turnstile || !gate) {
  return "Something is missing from the world.";
}

if (lever.location !== 'player:1') {
  return "You'll need to be holding the lever first.";
}

if (!gate.properties.locked) {
  return "The lever is already in place and the turnstile is functioning.";
}

gate.properties.locked = false;
turnstile.description = "The brass turnstile now has a rusty iron lever slotted into its side. It turns with a heavy, satisfying clunk.";
turnstile.name = "functional turnstile";
lever.location = "void";

return "You slide the rusty lever into the turnstile's empty socket. It fits with a metallic scrape. You give it a test push, and the turnstile rotates with a series of heavy clicks, unlocking the way forward.";

